import React, { useMemo } from 'react';
import { WellData } from '../types';

interface Props {
  results: WellData[];
  onSelectWell: (well: WellData) => void;
  selectedWellLabel?: string;
  lowOD: number;
  highOD: number;
}

const PlateOverview: React.FC<Props> = ({ results, onSelectWell, selectedWellLabel, lowOD, highOD }) => {
  if (results.length === 0) {
    return (
      <div className="h-96 flex flex-col items-center justify-center text-slate-400 bg-white rounded-lg border border-slate-200 border-dashed">
        <p>Process a file to view the plate overview.</p>
      </div>
    );
  }

  // Calculate grid dimensions dynamically
  const { rows, colCount, rowLabels } = useMemo(() => {
    let maxCol = 12; // Default min 12
    let maxRowIdx = 7; // Default min 8 rows (Index 7 is 'H')

    // Find extent of data
    results.forEach(w => {
        const rowMatch = w.label.match(/^[A-Za-z]+/);
        const colMatch = w.label.match(/\d+$/);

        if (rowMatch && colMatch) {
            const rowChar = rowMatch[0].toUpperCase();
            // Simple char code calc for single letters, adequate for plates < 26 rows
            const rIdx = rowChar.charCodeAt(0) - 65; 
            const cIdx = parseInt(colMatch[0]);

            if (rIdx > maxRowIdx) maxRowIdx = rIdx;
            if (cIdx > maxCol) maxCol = cIdx;
        }
    });

    const finalColCount = maxCol;

    // Generate Row Labels (A, B, C...)
    const finalRowLabels: string[] = [];
    for(let i=0; i<=maxRowIdx; i++) {
        finalRowLabels.push(String.fromCharCode(65 + i));
    }

    // Organize data into rows
    const rowsMap: Record<string, WellData[]> = {};
    finalRowLabels.forEach(r => { rowsMap[r] = [] });

    results.forEach(w => {
        const rowMatch = w.label.match(/^[A-Za-z]+/);
        if (rowMatch) {
            const r = rowMatch[0].toUpperCase();
            if (rowsMap[r]) rowsMap[r].push(w);
        }
    });

    // Sort wells within rows by column index
    Object.values(rowsMap).forEach(list => {
        list.sort((a, b) => {
             const colA = parseInt(a.label.match(/\d+$/)?.[0] || '0');
             const colB = parseInt(b.label.match(/\d+$/)?.[0] || '0');
             return colA - colB;
        });
    });

    return { rows: rowsMap, colCount: finalColCount, rowLabels: finalRowLabels };
  }, [results]);


  // Helper to get global max OD for consistent Y-axis scaling
  const allMaxOD = Math.max(...results.map(w => Math.max(...w.rawValues)));
  const yMax = allMaxOD > 0 ? allMaxOD * 1.1 : 1;

  return (
    <div className="bg-white p-4 rounded-lg shadow-sm border border-slate-200 overflow-x-auto">
      <div className="min-w-fit">
        {/* Header Row (Column Numbers) */}
        <div className="flex mb-2">
            <div className="w-8 shrink-0"></div> {/* Row label spacer */}
            {Array.from({ length: colCount }, (_, i) => i + 1).map(num => (
                <div key={num} className="flex-1 min-w-[32px] text-center text-xs font-bold text-slate-500">
                    {num}
                </div>
            ))}
        </div>

        {/* Grid Rows */}
        {rowLabels.map((rowLabel) => {
            const wells = rows[rowLabel] || [];

            // Create a sparse array for columns
            const cols = Array(colCount).fill(null);
            wells.forEach(w => {
                const colMatch = w.label.match(/\d+$/);
                if (colMatch) {
                    const colIdx = parseInt(colMatch[0]) - 1;
                    if (colIdx >= 0 && colIdx < colCount) cols[colIdx] = w;
                }
            });

            return (
                <div key={rowLabel} className="flex mb-2 h-16">
                    {/* Row Label */}
                    <div className="w-8 flex items-center justify-center font-bold text-slate-500 shrink-0">
                        {rowLabel}
                    </div>

                    {/* Columns */}
                    {cols.map((well: WellData | null, idx) => (
                        <div key={idx} className="flex-1 px-0.5 min-w-[32px]">
                            {well ? (
                                <Sparkline 
                                    well={well} 
                                    yMax={yMax} 
                                    isSelected={well.label === selectedWellLabel}
                                    onClick={() => onSelectWell(well)}
                                    lowOD={lowOD}
                                    highOD={highOD}
                                />
                            ) : (
                                <div className="w-full h-full bg-slate-50 rounded border border-slate-100 opacity-50"></div>
                            )}
                        </div>
                    ))}
                </div>
            );
        })}
      </div>
    </div>
  );
};

const Sparkline: React.FC<{
    well: WellData; 
    yMax: number; 
    isSelected: boolean; 
    onClick: () => void;
    lowOD: number;
    highOD: number;
}> = ({ well, yMax, isSelected, onClick, lowOD, highOD }) => {
    // Generate SVG path
    const width = 100;
    const height = 100; // coordinate space
    const xMax = well.dataPoints.length > 0 ? well.dataPoints[well.dataPoints.length - 1].timeValue : 1;

    // Polyline points
    const points = well.dataPoints.map(p => {
        const x = (p.timeValue / xMax) * width;
        const y = height - ((p.od / yMax) * height);
        return `${x},${y}`;
    }).join(' ');

    // Calculate Y positions for reference lines (low/high OD)
    const yLow = height - ((lowOD / yMax) * height);
    const yHigh = height - ((highOD / yMax) * height);

    return (
        <div 
            onClick={onClick}
            className={`
                w-full h-full rounded border relative cursor-pointer overflow-hidden group
                ${isSelected 
                    ? 'border-science-500 bg-science-50 ring-2 ring-science-200' 
                    : 'border-slate-200 bg-white hover:border-science-300'
                }
            `}
            title={`${well.label} ${well.name ? `- ${well.name}` : ''}\nDT: ${well.doublingTimeMin?.toFixed(1) ?? 'N/A'}`}
        >
            <div className="absolute top-0.5 left-0.5 text-[8px] sm:text-[10px] font-bold text-slate-500 group-hover:text-science-600 leading-none">
                {well.label}
            </div>

            {well.isHighInitialOD && (
                 <div className="absolute top-0.5 right-0.5 w-1.5 h-1.5 rounded-full bg-red-500" title="High Initial OD" />
            )}

            <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-full p-0.5" preserveAspectRatio="none">
                {/* Reference Range Band */}
                <rect 
                    x="0" 
                    y={Math.min(yHigh, yLow)} 
                    width={width} 
                    height={Math.abs(yHigh - yLow)} 
                    fill="#0ea5e9" 
                    fillOpacity="0.15" 
                />

                {/* Data Line */}
                <polyline 
                    points={points} 
                    fill="none" 
                    stroke={isSelected ? '#0284c7' : '#94a3b8'} 
                    strokeWidth="4" 
                />
            </svg>
        </div>
    );
}

export default PlateOverview;

import { ODDataPoint } from '../types';

// Regex for A1, A 1, P24, etc. 
// Updated to support rows A-Z (and potentially double letters) and up to 3 digits for columns to robustly support 384 well plates.
const WELL_PATTERN = /^[A-Za-z]{1,2}\s*\d{1,3}$/;

/**
 * Calculates linear regression for doubling time over the entire provided dataset.
 * Logic: ln(OD) = slope * time + intercept
 * Doubling Time = ln(2) / slope
 */
export const calculateRegression = (data: ODDataPoint[]): { slope: number; rSquared: number; dt: number | null } => {
  const n = data.length;
  if (n < 2) {
    return { slope: 0, rSquared: 0, dt: null };
  }

  let sumX = 0;
  let sumY = 0;
  let sumXY = 0;
  let sumXX = 0;
  let sumYY = 0;

  for (const point of data) {
    // We use time (assumed in minutes) for X
    const x = point.timeValue;
    // We use ln(OD) for Y
    const y = Math.log(point.od);

    sumX += x;
    sumY += y;
    sumXY += x * y;
    sumXX += x * x;
    sumYY += y * y;
  }

  const denominator = n * sumXX - sumX * sumX;
  if (denominator === 0) {
    return { slope: 0, rSquared: 0, dt: null };
  }

  const slope = (n * sumXY - sumX * sumY) / denominator;

  // R-squared calculation
  const intercept = (sumY - slope * sumX) / n;
  const ssTot = sumYY - (sumY * sumY) / n;
  const ssRes = sumYY - intercept * sumY - slope * sumXY;

  // Prevent division by zero or slightly negative variance due to float precision
  const rSquared = ssTot === 0 ? 0 : Math.max(0, 1 - (ssRes / ssTot));

  // DT = ln(2) / slope.
  let dtMin: number | null = null;
  if (slope > 0.0000001) { // Avoid divide by zero or negative growth
      dtMin = Math.log(2) / slope;
  }

  return { slope, rSquared, dt: dtMin };
};

/**
 * Calculates the "Inflection" Doubling Time.
 * Finds the steepest slope using a sliding window of 3 points (or 2 if only 2 exist)
 * within the provided valid data range.
 * Returns DT and the center point of that window (Inflection Point).
 */
export const calculateMaxSlopeRegression = (data: ODDataPoint[]): { dt: number; inflectionPoint: ODDataPoint } | null => {
    const n = data.length;
    if (n < 2) return null;

    // Transform all points to (time, lnOD) first to save repeated Math.log calls
    const points = data.map(p => ({ x: p.timeValue, y: Math.log(p.od) }));

    // Window size for local regression
    // If we have very few points, we just take the whole range (which is what calculating regression does)
    const WINDOW_SIZE = 3;

    if (n < WINDOW_SIZE) {
        // Fallback to overall slope if fewer points than window
        const { dt } = calculateRegression(data);
        if (dt === null) return null;
        // Return center point (or last point if len 2)
        const centerIndex = Math.floor((n - 1) / 2);
        return { 
            dt, 
            inflectionPoint: data[centerIndex]
        };
    }

    let maxSlope = -Infinity;
    let bestStartIndex = -1;

    // Sliding window
    for (let i = 0; i <= n - WINDOW_SIZE; i++) {
        const subset = points.slice(i, i + WINDOW_SIZE);

        // Simple linear regression on this subset
        let sumX = 0, sumY = 0, sumXY = 0, sumXX = 0;
        const m = subset.length;

        for (const p of subset) {
            sumX += p.x;
            sumY += p.y;
            sumXY += p.x * p.y;
            sumXX += p.x * p.x;
        }

        const denominator = m * sumXX - sumX * sumX;
        if (denominator !== 0) {
            const slope = (m * sumXY - sumX * sumY) / denominator;
            if (slope > maxSlope) {
                maxSlope = slope;
                bestStartIndex = i;
            }
        }
    }

    if (maxSlope > 0.0000001 && bestStartIndex !== -1) {
        // Identify the center point of the window as the inflection point
        const centerIndex = bestStartIndex + Math.floor(WINDOW_SIZE / 2);
        return {
            dt: Math.log(2) / maxSlope,
            inflectionPoint: data[centerIndex]
        };
    }

    return null;
};

/**
 * Sorts well labels (A1, A2... B1...)
 */
export const sortWells = (a: string, b: string): number => {
  const cleanA = a.toUpperCase().replace(/\s/g, '');
  const cleanB = b.toUpperCase().replace(/\s/g, '');

  const rowA = cleanA.charCodeAt(0);
  const rowB = cleanB.charCodeAt(0);

  if (rowA !== rowB) return rowA - rowB;

  const colMatchA = cleanA.match(/\d+/);
  const colMatchB = cleanB.match(/\d+/);

  const colA = colMatchA ? parseInt(colMatchA[0], 10) : 0;
  const colB = colMatchB ? parseInt(colMatchB[0], 10) : 0;

  return colA - colB;
};

export const isValidWell = (label: string): boolean => {
    return WELL_PATTERN.test(label.trim());
};

export const normalizeWellLabel = (label: string): string => {
  return label.toUpperCase().replace(/\s/g, '');
};

import { WellData, ProcessingConfig, ODDataPoint } from '../types';
import { calculateRegression, calculateMaxSlopeRegression, isValidWell, sortWells, normalizeWellLabel } from './mathUtils';
import { read, utils } from 'xlsx';

// Helper to parse layout grid
const parseLayout = (layoutText: string): Map<string, string> => {
  const nameMap = new Map<string, string>();
  if (!layoutText) return nameMap;

  const lines = layoutText.split(/\r\n|\n|\r/).filter(line => line.trim().length > 0);
  const rowLabels = "ABCDEFGHIJKLMNOPQRSTUVWXYZ".split(''); // Support up to 26 rows (A-Z) to cover 384 well (P) safely

  lines.forEach((line, rIdx) => {
      if (rIdx >= rowLabels.length) return;

      const cells = line.split('\t');
      cells.forEach((cell, cIdx) => {
          // Support 384 well (24 cols) and beyond. 
          // Standard 384 well is 16 rows x 24 cols.
          if (cIdx >= 48) return; 

          const label = `${rowLabels[rIdx]}${cIdx + 1}`;
          const cleanName = cell.trim();
          if (cleanName) {
              nameMap.set(label, cleanName);
          }
      });
  });
  return nameMap;
};

export const processFileContent = (
  content: string | ArrayBuffer, 
  config: ProcessingConfig,
  fileType: 'text' | 'binary',
  layoutInput?: string
): WellData[] => {

  let lines: any[][] = [];

  if (fileType === 'binary') {
    // Parse Excel
    const workbook = read(content, { type: 'array' });
    const firstSheetName = workbook.SheetNames[0];
    const worksheet = workbook.Sheets[firstSheetName];
    // Convert to array of arrays
    lines = utils.sheet_to_json(worksheet, { header: 1, defval: '' }) as any[][];
  } else {
    // Parse CSV/Text
    const textContent = content as string;
    // Handle universal newlines and potential tab delimiters
    lines = textContent.split(/\r\n|\n/).map(line => {
      // Basic separator detection per line to be robust
      const separator = line.includes('\t') ? '\t' : ',';
      return line.split(separator).map(c => c.trim().replace(/^"|"$/g, ''));
    });
  }

  // 1. Auto-detect Header Row
  let headerRowIndex = config.skipRows;
  let bestRowIndex = -1;
  let maxWellsFound = 0;

  const scanLimit = Math.min(lines.length, 100);

  for (let i = 0; i < scanLimit; i++) {
    const row = lines[i];
    if (!Array.isArray(row)) continue;

    let wellCount = 0;
    let hasTime = false;

    for (const cell of row) {
      if (cell === null || cell === undefined) continue;
      const val = String(cell).trim();
      if (isValidWell(val)) wellCount++;
      if (val.toLowerCase() === 'time') hasTime = true;
    }

    if (hasTime && wellCount > 0) {
      bestRowIndex = i;
      break; 
    }

    if (wellCount > maxWellsFound) {
      maxWellsFound = wellCount;
      bestRowIndex = i;
    }
  }

  if (bestRowIndex !== -1 && (maxWellsFound > 2 || (lines[bestRowIndex].some(c => String(c).toLowerCase() === 'time')))) {
    headerRowIndex = bestRowIndex;
  }

  if (lines.length < headerRowIndex + 1) {
    throw new Error(`File too short. Could not find header row (detected/configured at row ${headerRowIndex + 1}).`);
  }

  const headers = lines[headerRowIndex].map(h => String(h).trim());
  const dataRows = lines.slice(headerRowIndex + 1);

  // 2. Identify Well Columns and Time Column
  const wellIndices: number[] = [];
  let timeColIndex = -1;

  headers.forEach((h, idx) => {
    if (h && isValidWell(h)) {
      wellIndices.push(idx);
    }
    if (h && h.toLowerCase() === 'time') {
      timeColIndex = idx;
    }
  });

  if (wellIndices.length === 0) {
    throw new Error(`No valid well labels (e.g., A1, B2) found in header row ${headerRowIndex + 1}.`);
  }

  // 3. Initialize Well Data Structures
  const wellMap = new Map<string, number[]>();
  wellIndices.forEach(idx => {
    const label = headers[idx];
    wellMap.set(label, []);
  });

  // 4. Parse Data Rows
  let previousTime = -1;

  for (const row of dataRows) {
    if (!Array.isArray(row) || row.length === 0) continue;

    // Check for footer / end of block via Time column reset
    if (timeColIndex !== -1 && timeColIndex < row.length) {
      const timeValStr = String(row[timeColIndex]).trim();

      // Parse time to check for 0 reset or non-decreasing sequence which implies a new block
      // Formats: 0:29:16, 25:00:00, 1.05:30:00 (Days), or just seconds/minutes number
      let currentTimeVal = 0;

      if (timeValStr.includes(':')) {
         const parts = timeValStr.split(':').map(Number);
         // Handle HH:MM:SS or DD:HH:MM:SS loosely. 
         // If 3 parts: H:M:S. If 2 parts: M:S. 
         // Some readers might do D.HH:MM:SS. split(':') might leave D.HH as first part.
         if (parts.length === 3) {
            currentTimeVal = parts[0] * 3600 + (parts[1] || 0) * 60 + (parts[2] || 0);
         } else if (parts.length === 2) {
            currentTimeVal = parts[0] * 60 + (parts[1] || 0);
         }
      } else {
         currentTimeVal = parseFloat(timeValStr);
      }

      // If we have established a timeline and suddenly it drops to 0, stop.
      // We allow the first row to be 0 or small.
      if (!isNaN(currentTimeVal)) {
          // If time goes from >0 to 0, it's a reset.
          // Note: > 24h data usually keeps increasing (e.g. 25:00:00 or 90000s).
          // If format is Days and it parses to small numbers, previousTime check handles it unless it resets to 0.0.
          if (previousTime > 0 && currentTimeVal === 0) {
              break; // Stop processing, we hit the footer/next block
          }
          previousTime = currentTimeVal;
      }
    }

    if (!row.some(cell => cell !== null && cell !== undefined && cell !== '')) continue;

    wellIndices.forEach(colIdx => {
      if (colIdx >= row.length) return;

      const label = headers[colIdx];
      const val = row[colIdx];

      if (val !== undefined && val !== null && val !== '') {
          const num = parseFloat(val as string);
          if (!isNaN(num)) {
            wellMap.get(label)?.push(num);
          }
      }
    });
  }

  // Parse layout for names
  const nameMap = layoutInput ? parseLayout(layoutInput) : new Map<string, string>();

  // 5. Calculate Blank Curve (if applicable)
  let blankCurve: number[] = [];

  const rawBlanks = config.blankWells.split(',').map(s => s.trim()).filter(s => s.length > 0);
  const blankWellsSet = new Set<string>();

  rawBlanks.forEach(token => {
      // 1. Check if token is a direct well label (e.g. "H12")
      const normalized = normalizeWellLabel(token);
      if (wellMap.has(normalized)) {
          blankWellsSet.add(normalized);
      } else {
          // 2. Check if token matches a name (e.g. "Blank")
          // Find all wells with this name
          for (const [wellLabel, wellName] of nameMap.entries()) {
              if (wellName === token && wellMap.has(wellLabel)) {
                  blankWellsSet.add(wellLabel);
              }
          }
      }
  });

  const blanks = Array.from(blankWellsSet);

  if (blanks.length > 0) {
      // Find the length of the shortest dataset to avoid index out of bounds
      const minLen = Math.min(...blanks.map(b => wellMap.get(b)?.length || 0));

      if (minLen > 0) {
        blankCurve = new Array(minLen).fill(0);
        for (let i = 0; i < minLen; i++) {
            let sum = 0;
            for (const b of blanks) {
                sum += (wellMap.get(b)?.[i] || 0);
            }
            blankCurve[i] = sum / blanks.length;
        }
      }
  }

  // 6. Calculate DT for each well
  const results: WellData[] = [];

  wellMap.forEach((rawValues, label) => {
    // Subtract blank if available
    const correctedValues = rawValues.map((val, idx) => {
        if (blankCurve.length > idx) {
            return val - blankCurve[idx];
        }
        return val;
    });

    // Min/Max OD from corrected data
    const minOD = correctedValues.length > 0 ? Math.min(...correctedValues) : 0;
    const maxOD = correctedValues.length > 0 ? Math.max(...correctedValues) : 0;

    const dataPoints: ODDataPoint[] = correctedValues.map((od, idx) => ({
      timeValue: idx * config.timeInterval,
      od,
      included: od >= config.lowOD && od <= config.highOD
    }));

    // Filter points for calculations

    // a) Range-Included Points (for standard DT and range-inflection)
    const includedPoints = dataPoints.filter(p => p.included);

    // b) Valid Positive Points (for global inflection over entire curve)
    // Log(OD) requires OD > 0. Blank subtraction might make some negative/zero.
    const validGlobalPoints = dataPoints.filter(p => p.od > 0.0000001);

    const isHighInitialOD = dataPoints.length > 0 && dataPoints[0].od >= config.lowOD;

    // Standard Avg Regression
    const { slope, dt, rSquared } = calculateRegression(includedPoints);

    // Inflection (Steepest Slope) Regression - Within Range
    const inflectionRes = calculateMaxSlopeRegression(includedPoints);

    // Global Inflection (Steepest Slope) - Entire Curve
    const globalInflectionRes = calculateMaxSlopeRegression(validGlobalPoints);

    // Calculate Lag Time based on Global Inflection
    let lagTime: number | null = null;
    let doublingTimeGlobal: number | null = null;

    if (globalInflectionRes && globalInflectionRes.dt) {
        doublingTimeGlobal = globalInflectionRes.dt;

        // Slope = ln(2) / DT
        const slopeGlobal = Math.log(2) / globalInflectionRes.dt;
        const tInfl = globalInflectionRes.inflectionPoint.timeValue;
        const odInfl = globalInflectionRes.inflectionPoint.od;

        // Use the absolute minimum OD (or a small epsilon if 0/negative) as the baseline for Lag calculation
        // Equation: ln(OD_infl) = slope * (t_infl - t_lag) + ln(OD_min)
        // t_lag = t_infl - (ln(OD_infl) - ln(OD_min)) / slope
        const baselineOD = Math.max(minOD, 0.0001);
        if (baselineOD > 0 && odInfl > 0 && slopeGlobal > 0) {
             lagTime = tInfl - (Math.log(odInfl) - Math.log(baselineOD)) / slopeGlobal;
        }
    }

    results.push({
      label,
      name: nameMap.get(label), // Assign name
      rawValues: correctedValues, // Store corrected values for chart
      dataPoints,
      doublingTimeMin: dt,
      doublingTimeInflection: inflectionRes ? inflectionRes.dt : null,
      doublingTimeGlobal: doublingTimeGlobal,
      inflectionPoint: inflectionRes ? inflectionRes.inflectionPoint : null,
      globalInflectionPoint: globalInflectionRes ? globalInflectionRes.inflectionPoint : null,
      minOD,
      maxOD,
      lagTime,
      slope,
      rSquared,
      isHighInitialOD
    });
  });

  // 7. Sort results
  results.sort((a, b) => sortWells(a.label, b.label));

  return results;
};

import React, { useState, useCallback } from 'react';
